module top_module(
    input  A1  ,
    input  A2  ,
    input  A3  ,
    input  B1  ,
    input  B2  ,
    output X   ,
    input  VPB ,
    input  VPWR,
    input  VGND,
    input  VNB
);reg X_reg;
    wire sum1, sum2;

      wire _n01 = B1[0] ^ B2[0];
  wire _c01 = B1[0] & B2[0];
  wire _n02 = B1[1] ^ B2[1] ^ _c01;
  wire _c02 = (B1[1] & B2[1]) | (B1[1] & _c01) | (B2[1] & _c01);
  wire _n03 = B1[2] ^ B2[2] ^ _c02;
  wire _c03 = (B1[2] & B2[2]) | (B1[2] & _c02) | (B2[2] & _c02);
  wire _n04 = B1[3] ^ B2[3] ^ _c03;
  wire _c04 = (B1[3] & B2[3]) | (B1[3] & _c03) | (B2[3] & _c03);
  assign sum1 = {_n01, _n02, _n03, _n04};
    assign sum2 = A2 + A3;

    always @ (A1 or A2 or A3 or B1 or B2) begin
        if (A1 == 1) begin
            X_reg <= sum1;
        end else begin
            X_reg <= sum2;
        end
    end

    assign X = X_reg;

endmodule
